import { Icon } from "@iconify/vue";
import API from "@/services/api";
const MONTH_LABELS = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
const CHART_FONT = "Lexend, sans-serif";
const LABEL_STYLE = {
  colors: "#64748b",
  fontSize: "10px",
  fontFamily: CHART_FONT
};
const GRID_OPTS = {
  borderColor: "#252830",
  strokeDashArray: 4,
  xaxis: {
    lines: {
      show: false
    }
  }
};
export default {
  name: "Dashboard",
  data() {
    return {
      recentRecords: [],
      isLoadingRecords: false,
      chartReady: false,
      recordsError: ""
    };
  },
  computed: {
    // ── Stat cards ────────────────────────────────────────────────────
    totalCases() {
      return new Set(this.recentRecords.map(r => r.operationDetails?.operationName?.trim()).filter(Boolean)).size;
    },
    totalCountries() {
      return new Set(this.recentRecords.map(r => r.personalInformation?.country?.trim()).filter(Boolean)).size;
    },
    personsWithCases() {
      return this.recentRecords.filter(r => r.operationDetails?.operationName?.trim()).length;
    },
    // ── Table ─────────────────────────────────────────────────────────
    tableRecords() {
      return this.recentRecords.slice(0, 8);
    },
    // ── Country distribution (sorted desc) ───────────────────────────
    countryDistribution() {
      const map = {};
      this.recentRecords.forEach(r => {
        const c = r.personalInformation?.country?.trim();
        if (c) map[c] = (map[c] || 0) + 1;
      });
      return Object.entries(map).sort((a, b) => b[1] - a[1]).slice(0, 15);
    },
    // ── Nationality distribution ──────────────────────────────────────
    nationalityDistribution() {
      const map = {};
      this.recentRecords.forEach(r => {
        const n = r.personalInformation?.nationality?.trim();
        if (n) map[n] = (map[n] || 0) + 1;
      });
      return Object.entries(map).sort((a, b) => b[1] - a[1]).slice(0, 8);
    },
    // ── Monthly buckets ───────────────────────────────────────────────
    monthlySeries() {
      const now = new Date();
      const labels = [],
        persons = [],
        cases = [];
      for (let i = 11; i >= 0; i--) {
        const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
        labels.push(MONTH_LABELS[d.getMonth()]);
        const inMonth = this.recentRecords.filter(r => {
          if (!r.createdAt) return false;
          const rd = new Date(r.createdAt);
          return rd.getFullYear() === d.getFullYear() && rd.getMonth() === d.getMonth();
        });
        persons.push(inMonth.length);
        cases.push(new Set(inMonth.map(r => r.operationDetails?.operationName?.trim()).filter(Boolean)).size);
      }
      return {
        labels,
        persons,
        cases
      };
    },
    // ── Line chart ────────────────────────────────────────────────────
    lineChartOptions() {
      return {
        chart: {
          type: "line",
          background: "transparent",
          toolbar: {
            show: false
          },
          zoom: {
            enabled: false
          },
          fontFamily: CHART_FONT,
          animations: {
            enabled: true,
            speed: 500
          }
        },
        colors: ["#D97706", "#06b6d4"],
        stroke: {
          curve: "smooth",
          width: [2, 2]
        },
        markers: {
          size: 4,
          strokeWidth: 0
        },
        dataLabels: {
          enabled: false
        },
        grid: GRID_OPTS,
        xaxis: {
          categories: this.monthlySeries.labels,
          labels: {
            style: LABEL_STYLE
          },
          axisBorder: {
            show: false
          },
          axisTicks: {
            show: false
          }
        },
        yaxis: {
          labels: {
            style: LABEL_STYLE,
            formatter: v => Math.round(v)
          },
          min: 0
        },
        legend: {
          labels: {
            colors: "#9ca3af"
          },
          fontFamily: CHART_FONT,
          fontSize: "10px"
        },
        tooltip: {
          theme: "dark",
          style: {
            fontFamily: CHART_FONT
          }
        }
      };
    },
    lineChartSeries() {
      return [{
        name: "Personnel",
        data: this.monthlySeries.persons
      }, {
        name: "Cases",
        data: this.monthlySeries.cases
      }];
    },
    // ── Personnel by Country (horizontal bar) ─────────────────────────
    countryBarOptions() {
      return {
        chart: {
          type: "bar",
          background: "transparent",
          toolbar: {
            show: false
          },
          fontFamily: CHART_FONT,
          animations: {
            enabled: true,
            speed: 400
          }
        },
        plotOptions: {
          bar: {
            horizontal: true,
            borderRadius: 3,
            borderRadiusApplication: "end",
            barHeight: "65%"
          }
        },
        colors: ["#D97706"],
        fill: {
          type: "gradient",
          gradient: {
            shade: "dark",
            type: "horizontal",
            gradientToColors: ["#f59e0b"],
            stops: [0, 100]
          }
        },
        dataLabels: {
          enabled: true,
          style: {
            fontSize: "10px",
            fontFamily: CHART_FONT,
            colors: ["#000"]
          },
          formatter: v => v
        },
        grid: {
          ...GRID_OPTS,
          xaxis: {
            lines: {
              show: true
            }
          },
          yaxis: {
            lines: {
              show: false
            }
          }
        },
        xaxis: {
          labels: {
            style: LABEL_STYLE,
            formatter: v => Math.round(v)
          },
          axisBorder: {
            show: false
          },
          axisTicks: {
            show: false
          }
        },
        yaxis: {
          labels: {
            style: {
              ...LABEL_STYLE,
              colors: "#9ca3af"
            }
          }
        },
        legend: {
          show: false
        },
        tooltip: {
          theme: "dark",
          style: {
            fontFamily: CHART_FONT
          }
        }
      };
    },
    countryBarSeries() {
      return [{
        name: "Personnel",
        data: this.countryDistribution.map(([country, count]) => ({
          x: country,
          y: count
        }))
      }];
    },
    // ── Top 5 Operations (stacked bar) ───────────────────────────────
    topOperations() {
      const ops = {};
      this.recentRecords.forEach(r => {
        const op = r.operationDetails?.operationName?.trim();
        if (!op) return;
        if (!ops[op]) ops[op] = {
          active: 0,
          closed: 0
        };
        r.operationDetails?.disposition?.trim() ? ops[op].closed++ : ops[op].active++;
      });
      return Object.entries(ops).sort((a, b) => b[1].active + b[1].closed - (a[1].active + a[1].closed)).slice(0, 5);
    },
    barChartOptions() {
      const cats = this.topOperations.map(([name]) => name.length > 10 ? name.slice(0, 10) + "…" : name);
      return {
        chart: {
          type: "bar",
          background: "transparent",
          toolbar: {
            show: false
          },
          fontFamily: CHART_FONT,
          stacked: true,
          animations: {
            enabled: true,
            speed: 500
          }
        },
        colors: ["#06b6d4", "#D97706"],
        plotOptions: {
          bar: {
            columnWidth: "50%",
            borderRadius: 2,
            borderRadiusApplication: "end"
          }
        },
        grid: GRID_OPTS,
        xaxis: {
          categories: cats,
          labels: {
            style: {
              ...LABEL_STYLE,
              fontSize: "9px"
            },
            rotate: -25
          },
          axisBorder: {
            show: false
          },
          axisTicks: {
            show: false
          }
        },
        yaxis: {
          labels: {
            style: LABEL_STYLE,
            formatter: v => Math.round(v)
          },
          min: 0
        },
        legend: {
          show: false
        },
        dataLabels: {
          enabled: false
        },
        tooltip: {
          theme: "dark",
          style: {
            fontFamily: CHART_FONT
          }
        }
      };
    },
    barChartSeries() {
      return [{
        name: "Active",
        data: this.topOperations.map(([, v]) => v.active)
      }, {
        name: "Closed",
        data: this.topOperations.map(([, v]) => v.closed)
      }];
    },
    // ── Country treemap ───────────────────────────────────────────────
    treemapSeries() {
      return [{
        data: this.countryDistribution.map(([country, count]) => ({
          x: country,
          y: count
        }))
      }];
    },
    treemapOptions() {
      return {
        chart: {
          type: "treemap",
          background: "transparent",
          toolbar: {
            show: false
          },
          fontFamily: CHART_FONT,
          animations: {
            enabled: true,
            speed: 400
          }
        },
        colors: ["#D97706"],
        plotOptions: {
          treemap: {
            enableShades: true,
            shadeIntensity: 0.5,
            colorScale: {
              ranges: [{
                from: 1,
                to: 3,
                color: "#78350f"
              }, {
                from: 4,
                to: 8,
                color: "#b45309"
              }, {
                from: 9,
                to: 20,
                color: "#D97706"
              }, {
                from: 21,
                to: 999,
                color: "#f59e0b"
              }]
            }
          }
        },
        dataLabels: {
          style: {
            fontSize: "11px",
            fontFamily: CHART_FONT,
            colors: ["#000"]
          }
        },
        legend: {
          show: false
        },
        tooltip: {
          theme: "dark",
          style: {
            fontFamily: CHART_FONT
          },
          y: {
            formatter: v => `${v} personnel`
          }
        }
      };
    },
    // ── Nationality donut ─────────────────────────────────────────────
    nationalityDonutSeries() {
      return this.nationalityDistribution.map(([, count]) => count);
    },
    donutOptions() {
      const COLORS = ["#D97706", "#06b6d4", "#10b981", "#8b5cf6", "#ef4444", "#f97316", "#ec4899", "#6366f1"];
      return {
        chart: {
          type: "donut",
          background: "transparent",
          fontFamily: CHART_FONT,
          animations: {
            enabled: true,
            speed: 400
          }
        },
        colors: COLORS,
        labels: this.nationalityDistribution.map(([name]) => name),
        dataLabels: {
          enabled: false
        },
        legend: {
          position: "bottom",
          labels: {
            colors: "#9ca3af"
          },
          fontFamily: CHART_FONT,
          fontSize: "10px",
          itemMargin: {
            horizontal: 4,
            vertical: 2
          }
        },
        plotOptions: {
          pie: {
            donut: {
              size: "60%",
              labels: {
                show: true,
                total: {
                  show: true,
                  label: "Total",
                  color: "#9ca3af",
                  fontFamily: CHART_FONT,
                  fontSize: "10px",
                  formatter: w => w.globals.seriesTotals.reduce((a, b) => a + b, 0)
                }
              }
            }
          }
        },
        tooltip: {
          theme: "dark",
          style: {
            fontFamily: CHART_FONT
          },
          y: {
            formatter: v => `${v} personnel`
          }
        },
        stroke: {
          width: 2,
          colors: ["#1a1d24"]
        }
      };
    }
  },
  components: {
    Icon
  },
  methods: {
    async loadRecentRecords() {
      this.isLoadingRecords = true;
      this.chartReady = false;
      this.recordsError = "";
      try {
        const res = await API.get("/records");
        this.recentRecords = Array.isArray(res.data) ? res.data : [];
      } catch (err) {
        this.recordsError = err.response?.data?.message || "Unable to load records.";
      } finally {
        this.isLoadingRecords = false;
        await this.$nextTick();
        this.chartReady = true;
      }
    },
    formatRecordName(r) {
      return r.personalInformation?.name || "";
    },
    formatRecordCreatedAt(r) {
      if (!r.createdAt) return "—";
      return new Date(r.createdAt).toLocaleDateString("en-US", {
        month: "short",
        day: "numeric",
        year: "numeric"
      });
    }
  },
  mounted() {
    this.loadRecentRecords();
  }
};
